import{_ as t,o as e,c as r,a2 as d}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"新加坡股票交易规则与结算","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/trading-hours-and-rules/sg-trading-rules.md","filePath":"zh-CN/stock-trading/trading-hours-and-rules/sg-trading-rules.md"}'),h={name:"stock-trading/trading-hours-and-rules/sg-trading-rules.md"};function i(o,a,s,l,n,c){return e(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="新加坡股票交易规则与结算" tabindex="-1">新加坡股票交易规则与结算 <a class="header-anchor" href="#新加坡股票交易规则与结算" aria-label="Permalink to &quot;新加坡股票交易规则与结算&quot;">​</a></h1><p>新加坡股票市场的交易时段、持续交易规则及 T+2 交收机制说明。</p><h2 id="交易时间" tabindex="-1">交易时间 <a class="header-anchor" href="#交易时间" aria-label="Permalink to &quot;交易时间&quot;">​</a></h2><p>除公众假期外，新加坡股市一般于星期一至星期五交易。</p><h3 id="全日交易" tabindex="-1">全日交易 <a class="header-anchor" href="#全日交易" aria-label="Permalink to &quot;全日交易&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时段</th><th>时间</th><th>交易规则</th></tr></thead><tbody><tr><td>开市前时段</td><td>08:30 - 09:00</td><td>可委托下单，开市前最后一分钟内随机结束，之后为不可撤单时段</td></tr><tr><td>持续交易（早市）</td><td>09:00 - 12:00</td><td>可委托下单、改单、撤单</td></tr><tr><td>中午休市</td><td>12:00 - 13:00</td><td>休市</td></tr><tr><td>持续交易（午市）</td><td>13:00 - 17:00</td><td>可委托下单、改单、撤单</td></tr><tr><td>收市前时段</td><td>17:00 - 17:06</td><td>收市前最后一分钟内随机结束，之后为不可撤单时段</td></tr></tbody></table><h3 id="半日交易" tabindex="-1">半日交易 <a class="header-anchor" href="#半日交易" aria-label="Permalink to &quot;半日交易&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时段</th><th>时间</th><th>交易规则</th></tr></thead><tbody><tr><td>开市前时段</td><td>08:30 - 09:00</td><td>同全日交易</td></tr><tr><td>持续交易</td><td>09:00 - 12:00</td><td>可委托下单、改单、撤单</td></tr><tr><td>收市前时段</td><td>12:00 - 12:06</td><td>收市前最后一分钟内随机结束</td></tr></tbody></table><h2 id="交易与交收机制" tabindex="-1">交易与交收机制 <a class="header-anchor" href="#交易与交收机制" aria-label="Permalink to &quot;交易与交收机制&quot;">​</a></h2><h3 id="日内交易" tabindex="-1">日内交易 <a class="header-anchor" href="#日内交易" aria-label="Permalink to &quot;日内交易&quot;">​</a></h3><p>日内交易（Day Trade）是指在同一交易日内买入或卖出某只股票头寸，也称 T+0 交易。长桥新加坡账户可进行无限制的日内交易，但须遵守设定的信用额度。</p><h3 id="结算规则" tabindex="-1">结算规则 <a class="header-anchor" href="#结算规则" aria-label="Permalink to &quot;结算规则&quot;">​</a></h3><p>新交所产品按 T+2 结算，即交易日后第 2 个工作日完成结算。如第二天是公共假期，则顺延至下一个工作日。</p><h3 id="每手买卖单位" tabindex="-1">每手买卖单位 <a class="header-anchor" href="#每手买卖单位" aria-label="Permalink to &quot;每手买卖单位&quot;">​</a></h3><p>标准交易单位为每手 100 股。部分产品（如 ETF、ADR、固定收益工具等）可能以其他交易单位交易。</p><p>新交所设有碎股交易市场，可以低于 1 手的数量进行碎股交易。</p><h3 id="最小报价单位" tabindex="-1">最小报价单位 <a class="header-anchor" href="#最小报价单位" aria-label="Permalink to &quot;最小报价单位&quot;">​</a></h3><p>最小报价单位（MBS）是指证券价格可以变动的最小幅度，不同产品类型和价格区间的最小报价单位不同，具体请参考新交所官网。</p><h2 id="sips-cka-car" tabindex="-1">SIPs / CKA / CAR <a class="header-anchor" href="#sips-cka-car" aria-label="Permalink to &quot;SIPs / CKA / CAR&quot;">​</a></h2><h3 id="什么是-sips" tabindex="-1">什么是 SIPs <a class="header-anchor" href="#什么是-sips" aria-label="Permalink to &quot;什么是 SIPs&quot;">​</a></h3><p>特定投资产品（Specified Investment Products，SIPs）是指比普通股票更复杂的金融产品，包括期货、期权、窝轮、ETF、ETN、杠杆式外汇、CFD 等。</p><p>长桥新加坡支持交易的 SIPs 包括：美股期权、港股窝轮、新加坡 DLC（每日杠杆证书）、各市场 ETF。</p><h3 id="什么是-cka-car" tabindex="-1">什么是 CKA / CAR <a class="header-anchor" href="#什么是-cka-car" aria-label="Permalink to &quot;什么是 CKA / CAR&quot;">​</a></h3><p>CKA（客户知识评估）和 CAR（客户评价账户）是新加坡金融管理局（MAS）推行的评估机制。投资者必须通过这两项测试才能交易 SIPs 产品。</p><p>如未通过 CKA/CAR，下单 SIPs 产品时系统会提示完成测评，通过后方可交易。</p><h2 id="dlc-每日杠杆证书" tabindex="-1">DLC 每日杠杆证书 <a class="header-anchor" href="#dlc-每日杠杆证书" aria-label="Permalink to &quot;DLC 每日杠杆证书&quot;">​</a></h2><p>DLC（Daily Leverage Certificates）是一种金融衍生品，为投资者提供标的资产（如市场指数或个股）每日表现最高 7 倍的固定杠杆。</p><p>基本原则：如标的资产较前一交易日收盘价波动 1%，3 倍 DLC 的价值将波动 3%，7 倍 DLC 的价值将波动 7%。</p><p>DLC 适合对复杂产品具有投资知识且有高风险承受能力的投资者。投资者需具备 SIP 交易资格才能投资 DLC。</p><p>更多信息请参考新加坡交易所官网：<a href="https://www2.sgx.xn--com-7k2ex12dpt6dtgd2r41ayea" target="_blank" rel="noreferrer">https://www2.sgx.com（路径：证券</a> - 产品 - DLC，右上角可切换中英文）</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/订单类型/限价单与市价单">限价单与市价单</a> — 订单类型</li></ul>',32)])])}const b=t(h,[["render",i]]);export{u as __pageData,b as default};
